from pyspark.sql import functions as F
from pyspark.sql.window import Window
import re
import uuid


def clean_str(col):
    return F.trim(F.col(col).cast("string"))


def nullify_str(col):
    s = F.trim(col.cast("string"))
    return (
        F.when(col.isNull(), None)
         .when(F.lower(s).isin("undefined", "null", "none", ""), None)
         .otherwise(s)
    )


def make_uuid(x):
    if x is None:
        return None
    return str(uuid.uuid5(uuid.NAMESPACE_DNS, str(x)))


uuid_udf = F.udf(make_uuid)
